import numpy as np
import math

from resp_sp.algorithm import compute_power_spectrum
from resp_sp.signal_processing import PreProcessing
from resp_sp.utils import process_output, find_max_peak, min_max_scale, normalize_to_distribution, sliding_window_multi
from resp_sp.sqa import calculate_sqa

import logging
logger = logging.getLogger(__name__)

class CalculateSpo2UsingFrequencyAnalysis():
    """
    A class to represent the result of a SpO2 calculation using frequency analysis approach.

    Parameters
    ----------
    params_set : int
        Set of the pre-defined parameters to use for SpO2 calculation.
    """
    
    def __init__(self, params_set: int):
        """
        Initialize parameters for the processing.

        Parameters
        ----------
        params_set : int
            Set of the pre-defined parameters to use for SpO2 calculation.
        """
        self.params_spo2 = self.params_to_calculate_spo2(params_set)
        self.spo2_bandpass = self.params_spo2["spo2_minmax"]
            
    
    def params_to_calculate_spo2(self, params_set):
        if params_set == 1:
            return {
                "sampling_time": 0.04,
                "window_mva": 5,
                "window_size": int(20 / 0.04),
                "window_shift": 25,  # shift every 1s

                # "sqa_bandpass_spo2_individual_frame": 0.65,
                "sqa_threshold_individual_frame": 0.65,
                "sqa_threshold_pos_to_neg_peak": 0.9,
                "spo2_bandpass": [0.5, 3],
                "spo2_minmax": [70, 100],
            }
        elif params_set == 2:
            return {
                "sampling_time": 0.04,
                "window_mva": 5,
                "window_size": int(20 / 0.04),
                "window_shift": 25,  # shift every 1s

                # "sqa_bandpass_spo2_individual_frame": 0.65,
                "sqa_threshold_individual_frame": 0.1,
                "sqa_threshold_pos_to_neg_peak": 0.1,
                "spo2_bandpass": [0.5, 3],
                "spo2_minmax": [70, 100],
            }
        elif params_set == 3:
            return {
                "sampling_time": 0.04,
                "window_mva": 3,
                "window_size": int(10 / 0.04),
                "window_shift": 25,  # shift every 1s

                # "sqa_bandpass_spo2_individual_frame": 0.65,
                "sqa_threshold_individual_frame": 0.1,
                "sqa_threshold_pos_to_neg_peak": 0.1,
                "spo2_bandpass": [0.5, 3],
                "spo2_minmax": [70, 100],
            }
        elif params_set == 4:
            return {
                "sampling_time": 0.04,
                "window_mva": 5,
                "window_size": int(20 / 0.04),
                "window_shift": 25,  # shift every 1s

                # "sqa_bandpass_spo2_individual_frame": 0.65,
                "sqa_threshold_individual_frame": 0.3,
                "sqa_threshold_pos_to_neg_peak": 0.1,
                "spo2_bandpass": [0.5, 3],
                "spo2_minmax": [70, 100],
            }
    
        

    def run_preprocessing(self, timestamp, pd_red, pd_ir, window_mva):
        preprocessing = PreProcessing()

        pd_red_mva_time, pd_red_mva_val = preprocessing.moving_average_filter(timestamp, pd_red, window_mva)
        pd_ir_mva_time, pd_ir_mva_val = preprocessing.moving_average_filter(timestamp, pd_ir, window_mva)
        
        pd_red_mva = np.vstack([pd_red_mva_time, pd_red_mva_val]).T
        pd_ir_mva = np.vstack([pd_ir_mva_time, pd_ir_mva_val]).T
        return pd_red_mva, pd_ir_mva


    def get_spo2(self, x, spo2_bandpass=None, spo2_equation=6, round_value=True):

        if spo2_bandpass is None:
            spo2_min = -1
            spo2_max = 101
        else:
            spo2_min = spo2_bandpass[0]
            spo2_max = spo2_bandpass[1]

        try:
            if spo2_equation == 1:
                # spo2 = -11.55662048527909*x + 98.26367177880022
                # spo2 = -11.55662048527909*x + 100.26367177880022
                spo2 = -11.55662048527909*x + 102.26367177880022 # 20s new FDA line
                # spo2 = -11.55662048527909*x + 105.26367177880022
                # spo2 = -11.55662048527909*x + 107.26367177880022
                # spo2 = -11.55662048527909*x + 109.26367177880022
                # spo2 = -11.55662048527909*x + 111.26367177880022
                # spo2 = -11.55662048527909*x + 113.26367177880022
            elif spo2_equation == 2:
                spo2 = -21.03*x + 102.16 # optimized from Clinimark dataset
            elif spo2_equation == 3: # optimized from UCSF2024 - resp1+resp2
                spo2 = -22.46*x + 102.28
            elif spo2_equation == 4: # optimized from UCSF2024 - resp1
                spo2 = -24.16*x + 103.09 
            elif spo2_equation == 5: # optimized from UCSF2024 - resp2
                spo2 = -21.21*x + 101.75
            elif spo2_equation == 6: # new line
                spo2 = -24.71*x + 103.57
            elif spo2_equation == 7: # test
                spo2 = -22.91*x + 102.52
            elif spo2_equation == 8: # modified from eq1 - this is to use with R norm
                spo2 = -11.55662048527909*x + 105.26367177880022
            elif spo2_equation == 9: # modified from eq1 - this is to use with sensor v3.0
                spo2 = -11.55662048527909*x + 104.26367177880022
            
            spo2[spo2>spo2_max] = spo2_max
            spo2[spo2<spo2_min] = np.nan

            if round_value:
                for i in range(len(spo2)):
                    if spo2[i]%1>=0.5:
                        spo2[i] = np.ceil(spo2[i])
                    else:
                        spo2[i] = np.floor(spo2[i])
        except:
            spo2 = [] #np.nan
        return spo2


    def check_signal_quality(self, data, fs, bandpass, threshold_center, threshold_left, threshold_right):

        sqa_index_center, sqa_index_left, sqa_index_right, first_magpeak, second_magpeak, freq_bp, mag_bp = calculate_sqa(data, 2**12, fs, bandpass, 0.01)

        if (sqa_index_center<threshold_center) or (sqa_index_left<threshold_left) or (sqa_index_right<threshold_right):
            # print('Fail SQA red {}, {}, {}'.format(sqa_index_center_red, sqa_index_left_red, sqa_index_right_red))
            is_fail = True
        else:
            is_fail = False
        return {
            "is_fail": is_fail,
            "sqa_index_center": sqa_index_center,
            "sqa_index_left": sqa_index_left,
            "sqa_index_right": sqa_index_right,
            "first_magpeak": first_magpeak,
            "second_magpeak": second_magpeak,
            "freq_bp": freq_bp,
            "mag_bp": mag_bp
        }

    def calculate_spo2(
        self,
        timestamp,
        pd_red,
        pd_ir,
        spo2_equation=6,
        enable_quality_check=False,
        spo2_bandpass=None,
        round_value=True,
        norm_r=None
    ):
        """
        Calculate SpO2 using a sliding window and frequency analysis approach.

        Parameters
        ----------
        timestamp : numpy.ndarray
            1D array of timestamps for the signal.
        pd_red : numpy.ndarray
            1D array of photodiode signal from the RED LED.
        pd_ir : numpy.ndarray
            1D array of photodiode signal from the IR LED.
        spo2_equation : int, optional
            Selects the pre-defined SpO2 equation to use. Defaults to 6.
        enable_quality_check : bool, optional
            If True, only use windows that pass the signal quality check. Defaults to False.
        spo2_bandpass : list or None, optional
            Frequency bandpass for SpO2 calculation, e.g., [min, max]. If None, uses default from params. Defaults to None.
        round_value : bool, optional
            If True, round the SpO2 values to the nearest integer. Defaults to True.
        norm_r : dict or None, optional
            Normalization configuration for the R coefficient. Must be a dict:
                {
                    "method": one of ["offset_mean", "min_max_scale", "norm_to_distribution"],
                    "params":
                        if "offset_mean": float (r_offset)
                        if "min_max_scale": tuple (feature_range, data_range)
                        if "norm_to_distribution": tuple (target_mean_std, original_mean_std)
                }
            If None, no normalization is applied.

        Returns
        -------
        dict
            Dictionary containing:
                timestamp : numpy.ndarray
                    Timestamps corresponding to each computed SpO2 value.
                spo2 : numpy.ndarray
                    Computed SpO2 values.
                coeff_r : numpy.ndarray
                    R coefficient values used for SpO2 calculation.
                pi_ir : numpy.ndarray
                    Perfusion index of the IR signal.
                pi_red : numpy.ndarray
                    Perfusion index of the RED signal.
                sqa_center_ir : numpy.ndarray
                    Signal quality index (center) for IR.
                sqa_left_ir : numpy.ndarray
                    Signal quality index (left) for IR.
                sqa_right_ir : numpy.ndarray
                    Signal quality index (right) for IR.
                sqa_center_red : numpy.ndarray
                    Signal quality index (center) for RED.
                sqa_left_red : numpy.ndarray
                    Signal quality index (left) for RED.
                sqa_right_red : numpy.ndarray
                    Signal quality index (right) for RED.
                raw_red : list of numpy.ndarray
                    RED signal in each sliding window.
                raw_ir : list of numpy.ndarray
                    IR signal in each sliding window.
                index : numpy.ndarray
                    Array indices corresponding to the SpO2 values.
                bpm : numpy.ndarray
                    Estimated beats per minute for each window.
                processed_spo2 : float
                    Median value of all computed SpO2 values.
                processed_spo2_sd : float
                    Standard deviation of all computed SpO2 values.
                total_frame : int
                    Total number of frames processed.
                accepted_frame : int
                    Number of frames accepted (passed quality check).


        Raises
        ------
        ValueError
            If norm_r is not a valid dict or contains an invalid method.
        """

        if spo2_bandpass is not None:
            self.spo2_bandpass = spo2_bandpass

        # Validate norm_r
        allowed_methods = ["offset_mean", "min_max_scale", "norm_to_distribution"]
        r_offset = None
        norm_r_min_max_scale = None
        norm_r_to_distribution = None

        if norm_r is not None:
            if not isinstance(norm_r, dict) or "method" not in norm_r or "params" not in norm_r:
                raise ValueError(
                    'norm_r must be a dict with keys "method" and "params".'
                )
            if norm_r["method"] not in allowed_methods:
                raise ValueError(
                    f'norm_r["method"] must be one of {allowed_methods}, but got {norm_r["method"]}'
                )
            if norm_r["method"] == "offset_mean":
                r_offset = norm_r["params"]
            elif norm_r["method"] == "min_max_scale":
                norm_r_min_max_scale = norm_r["params"]
            elif norm_r["method"] == "norm_to_distribution":
                norm_r_to_distribution = norm_r["params"]
        

        # extract params to calculate spo2
        wlength = self.params_spo2["window_size"]
        wshift = self.params_spo2["window_shift"]
        bandpass = self.params_spo2["spo2_bandpass"]
        window_mva = self.params_spo2["window_mva"]
        sampling_time = self.params_spo2["sampling_time"]
        fs = 1/sampling_time
        sqa_threshold_individual_frame = self.params_spo2["sqa_threshold_individual_frame"]
        sqa_threshold_pos_to_neg_peak = self.params_spo2["sqa_threshold_pos_to_neg_peak"]
        

        pd_red_mva, pd_ir_mva = self.run_preprocessing(timestamp, pd_red, pd_ir, window_mva)

        index_mva = np.arange(len(timestamp))
        index_mva = index_mva[int(math.floor(window_mva/2)):(len(index_mva)-int(math.floor(window_mva/2)))]


        total_frame = 0 # total number of frame
        accepted_frame = 0 # number of selected frame

        output_timestamp = [] # timestamp
        output_coeff_r = [] # cofficient for SpO2 calculation

        output_pi_ir = []
        output_pi_red = []

        output_sqa_center_ir = []
        output_sqa_left_ir = []
        output_sqa_right_ir = []

        output_sqa_center_red = []
        output_sqa_left_red = []
        output_sqa_right_red = []

        output_index = []

        output_bpm = []

        save_raw_red = []
        save_raw_ir = []

        # for i in range(0, len(pd_ir_mva)-wlength, wshift):
        for window_red, window_ir, window_index,  in sliding_window_multi(wlength, wshift, pd_red_mva, pd_ir_mva, index_mva.reshape(-1, 1)):
            # print(current_window_pd_red.shape, current_window_pd_ir.shape, current_index.shape)
            
            total_frame+=1 # add to total number of frame

            # window_red = pd_red_mva[i:i+wlength, :]
            # window_ir = pd_ir_mva[i:i+wlength, :]

            # current_time = pd_ir_mva[i+wlength, 0]
            # current_time = current_window_pd_red[-1, 0] # timestamp of the last value in the current window
            # output_timestamp = np.append(output_timestamp, current_time) # timestamp
            current_time = window_red[-1, 0]

            # current_index = index_mva[i+wlength]
            current_index = window_index[-1]

            # print(window_red[-1,:], window_ir[-1, :], current_time, current_index)
            
            # sqa check for red pd
            pd_red_ac = window_red[:, 1] # ac component of red pd
            pd_red_dc = np.mean(pd_red_ac) # dc component of red pd

            sqa_index_center_red, sqa_index_left_red, sqa_index_right_red, first_magpeak_red, second_magpeak_red, freq_bp, mag_bp = calculate_sqa(pd_red_ac, 2**12, fs, bandpass, 0.01)
            if enable_quality_check:
                res_sqa_check_red = self.check_signal_quality(pd_red_ac, fs, bandpass, sqa_threshold_individual_frame, sqa_threshold_pos_to_neg_peak, sqa_threshold_pos_to_neg_peak)
                if res_sqa_check_red["is_fail"]:
                    continue

            
            # sqa check for ir pd
            pd_ir_ac = window_ir[:, 1]
            pd_ir_dc = np.mean(pd_ir_ac)

            sqa_index_center_ir, sqa_index_left_ir, sqa_index_right_ir, first_magpeak_ir, second_magpeak_ir, freq_bp, mag_bp = calculate_sqa(pd_ir_ac, 2**12, fs, bandpass, 0.01)

            if enable_quality_check:
                res_sqa_check_ir = self.check_signal_quality(pd_ir_ac, fs, bandpass, sqa_threshold_individual_frame, sqa_threshold_pos_to_neg_peak, sqa_threshold_pos_to_neg_peak)
                if res_sqa_check_ir["is_fail"]:
                    continue
            
            pd_red_dc_freq, pd_red_dc_mag = compute_power_spectrum(pd_red_ac, fs)
            pd_ir_dc_freq, pd_ir_dc_mag = compute_power_spectrum(pd_ir_ac, fs)

            pd_red_dc_mag_peak = pd_red_dc_mag[0]
            pd_ir_dc_mag_peak = pd_ir_dc_mag[0]


            pd_red_ac_freq, pd_red_ac_mag = compute_power_spectrum(pd_red_ac-pd_red_dc, fs)
            pd_ir_ac_freq, pd_ir_ac_mag = compute_power_spectrum(pd_ir_ac-pd_ir_dc, fs)
            
            
            pd_red_ac_freq_peak, pd_red_ac_mag_peak = find_max_peak(pd_red_ac_freq, pd_red_ac_mag, bandpass)
            pd_ir_ac_freq_peak, pd_ir_ac_mag_peak = find_max_peak(pd_ir_ac_freq, pd_ir_ac_mag, bandpass)


            coeff_r = (pd_red_ac_mag_peak/pd_red_dc_mag_peak) / (pd_ir_ac_mag_peak/pd_ir_dc_mag_peak)

            output_coeff_r = np.append(output_coeff_r, coeff_r)
            output_timestamp = np.append(output_timestamp, current_time) # timestamp
            output_index = np.append(output_index, current_index)

            try:
                if len(pd_ir_ac_freq_peak)<1:
                    pd_ir_ac_freq_peak = np.nan
            except:
                pass
            output_bpm = np.append(output_bpm, pd_ir_ac_freq_peak * 60)

            # AC and DC components
            red_ac = np.max(window_red) - np.min(window_red)
            red_dc = np.mean(window_red)
            ir_ac = np.max(window_ir) - np.min(window_ir)
            ir_dc = np.mean(window_ir)

            output_pi_ir = np.append(output_pi_ir, ir_ac/ir_dc*100)
            output_pi_red = np.append(output_pi_red, red_ac/red_dc*100)
            
            output_sqa_center_ir = np.append(output_sqa_center_ir, sqa_index_center_ir)
            output_sqa_left_ir = np.append(output_sqa_left_ir, sqa_index_left_ir)
            output_sqa_right_ir = np.append(output_sqa_right_ir, sqa_index_right_ir)

            output_sqa_center_red = np.append(output_sqa_center_red, sqa_index_center_red)
            output_sqa_left_red = np.append(output_sqa_left_red, sqa_index_left_red)
            output_sqa_right_red = np.append(output_sqa_right_red, sqa_index_right_red)

            save_raw_red.append(window_red)
            save_raw_ir.append(window_ir)

            accepted_frame+=1

        if len(output_coeff_r) > 0:
            if r_offset is not None:
                output_coeff_r = output_coeff_r + r_offset  # add offset to the coefficient
            elif norm_r_min_max_scale is not None:
                output_coeff_r = min_max_scale(output_coeff_r, norm_r_min_max_scale[0], norm_r_min_max_scale[1])
            elif norm_r_to_distribution is not None:
                output_coeff_r = normalize_to_distribution(output_coeff_r, norm_r_to_distribution[0], norm_r_to_distribution[1])


        output_spo2 = self.get_spo2(output_coeff_r, spo2_bandpass=self.spo2_bandpass, spo2_equation=spo2_equation, round_value=round_value)

        processed_spo2 = process_output(output_spo2, 3, "median", True)
        processed_spo2_sd = process_output(output_spo2, 3, "sd", True)

        return {
            "timestamp": output_timestamp,
            "spo2": output_spo2,
            "coeff_r": output_coeff_r,
            "pi_ir": output_pi_ir,
            "pi_red":  output_pi_red,
            "sqa_center_ir": output_sqa_center_ir,
            "sqa_left_ir": output_sqa_left_ir,
            "sqa_right_ir": output_sqa_right_ir,
            "sqa_center_red": output_sqa_center_red,
            "sqa_left_red": output_sqa_left_red,
            "sqa_right_red": output_sqa_right_red,
            "raw_red": save_raw_red,
            "raw_ir": save_raw_ir,
            "index": output_index,
            "bpm": output_bpm,
            "processed_spo2": processed_spo2,
            "processed_spo2_sd": processed_spo2_sd,
            "total_frame": total_frame,
            "accepted_frame": accepted_frame
        }